1323 |     /**
1324 |      * Tries to parse JSON. If it fails due to bad escaping (common with AI),
1325 |      * it attempts to double-escape backslashes that aren't valid JSON control chars.
1326 |      */
1327 |     function smartJSONParse(jsonString) {
1328 |         try {
1329 |             return JSON.parse(jsonString);
1330 |         } catch (e) {
1331 |             console.warn("Standard JSON parse failed, attempting Robust Auto-Fix...");
1332 |             let fixed = jsonString
1333 |                 // 1. Fix backslashes that aren't part of a valid escape sequence
1334 |                 .replace(/\\(?!["\\/bfnrtu])/g, "\\\\")
1335 |                 // 2. Fix literal newlines inside strings (replace with \n)
1336 |                 .replace(/(\n)/g, (match, p1, offset) => {
1337 |                     // Only replace if we are likely inside a quoted string
1338 |                     const before = jsonString.slice(0, offset);
1339 |                     const quoteCount = (before.match(/"/g) || []).length;
1340 |                     return (quoteCount % 2 === 1) ? "\\n" : "\n";
1341 |                 });
1342 | 
1343 |             try {
1344 |                 const cleanObj = JSON.parse(fixed);
1345 |                 document.getElementById('json-input').value = fixed;
1346 |                 if (typeof saveState === 'function') saveState();
1347 |                 showGlobalToast("✨ Robust Auto-Correction Applied");
1348 |                 return cleanObj;
1349 |             } catch (e2) {
1350 |                 console.error("Robust fix failed:", e2);
1351 |                 throw e; // Throw original error for better debugging
1352 |             }
1353 |         }
1354 |     }
