1532 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
1533 |     function applyLocalPatch(content, ops) {
1534 |         let lines = content.split('\n');
1535 |         let logs = [];
1536 |         let success = true;
1537 | 
1538 |         if (typeof ops === 'string') {
1539 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
1540 |         }
1541 | 
1542 |         ops.forEach(op => {
1543 |             if (op.action === 'comment') return;
1544 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
1545 |             
1546 |             if (op.action === 'replace_block') {
1547 |                 // Strategy 1: Exact String Match (Fastest)
1548 |                 const currentStr = lines.join('\n');
1549 |                 if (currentStr.includes(op.find_block)) {
1550 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
1551 |                     logs.push('Exact match applied');
1552 |                     return;
1553 |                 }
1554 | 
1555 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
1556 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
1557 |                 if (searchLines.length === 0) return;
1558 | 
1559 |                 let matchStart = -1;
1560 |                 let matchEnd = -1;
1561 | 
1562 |                 // Scan file lines
1563 |                 for (let i = 0; i < lines.length; i++) {
1564 |                     // If first line matches (ignoring whitespace)
1565 |                     if (lines[i].trim() === searchLines[0]) {
1566 |                         // Check subsequent lines
1567 |                         let allMatch = true;
1568 |                         let fileOffset = 0;
1569 |                         let searchOffset = 1;
1570 |                         
1571 |                         while (searchOffset < searchLines.length) {
1572 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
1573 |                             const nextFile = lines[i + fileOffset + 1].trim();
1574 |                             // Skip empty lines in file if they aren't in search block
1575 |                             if (nextFile === '') {
1576 |                                 fileOffset++;
1577 |                                 continue;
1578 |                             }
1579 |                             if (nextFile !== searchLines[searchOffset]) {
1580 |                                 allMatch = false;
1581 |                                 break;
1582 |                             }
1583 |                             fileOffset++;
1584 |                             searchOffset++;
1585 |                         }
1586 | 
1587 |                         if (allMatch) {
1588 |                             matchStart = i;
1589 |                             matchEnd = i + fileOffset;
1590 |                             break;
1591 |                         }
