3996 |     function formatBytes(bytes) {
3997 |         if (!bytes) return '0 B';
3998 |         const k = 1024;
3999 |         const sizes = ['B', 'KB', 'MB', 'GB'];
4000 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
4001 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
4002 |     }
