4004 |     function timeAgo(dateString) {
4005 |         const date = new Date(dateString);
4006 |         const now = new Date();
4007 |         const seconds = Math.floor((now - date) / 1000);
4008 |         if (seconds < 10) return 'just now';
4009 |         if (seconds < 60) return seconds + 's ago';
4010 |         const minutes = Math.floor(seconds / 60);
4011 |         if (minutes < 60) return minutes + 'm ago';
4012 |         const hours = Math.floor(minutes / 60);
4013 |         if (hours < 24) return hours + 'h ago';
4014 |         return date.toLocaleDateString();
4015 |     }
