5139 |         
5140 |         if(!diffLeft) {
5141 |             diffLeft = ace.edit("diff-left");
5142 |             diffLeft.setTheme("ace/theme/tomorrow_night_bright");
5143 |             diffLeft.setReadOnly(true);
5144 |             diffLeft.setOption("showPrintMargin", false);
