5149 |             diffRight.setOption("showPrintMargin", false);
5150 | 
5151 |             diffLeft.session.on('changeScrollTop', (top) => diffRight.session.setScrollTop(top));
5152 |             diffRight.session.on('changeScrollTop', (top) => diffLeft.session.setScrollTop(top));
5153 |             diffLeft.session.on('changeScrollLeft', (left) => diffRight.session.setScrollLeft(left));
5154 |             diffRight.session.on('changeScrollLeft', (left) => diffLeft.session.setScrollLeft(left));
5155 |         }
5156 | 
5157 |         diffLeft.setValue("Loading...", -1);
5158 |         diffRight.setValue("Loading...", -1);
5159 | 
5160 |         try {
5161 |             let leftContent = "", rightContent = "";
5162 | 
5163 |             if (forcedLeft !== null && forcedRight !== null) {
5164 |                 leftContent = forcedLeft;
5165 |                 rightContent = forcedRight;
5166 |             } else {
5167 |                 const rightRef = data.commit_sha || 'HEAD';
5168 |                 const leftRef = rightRef + '^';
5169 | 
5170 |                 const fetchFile = async (ref) => {
5171 |                     const res = await fetch(CONFIG.funcUrl, {
5172 |                         method: 'POST', headers: {'Content-Type': 'application/json'},
5173 |                         body: apiBody({ action: 'preview_file', file_path: data.file, ref_sha: ref })
5174 |                     });
5175 |                     const d = await res.json();
5176 |                     return d.content ? b64DecodeUnicode(d.content) : '';
5177 |                 };
5178 | 
5179 |                 const results = await Promise.all([
5180 |                     fetchFile(leftRef).catch(() => ""),
5181 |                     fetchFile(rightRef).catch(() => "")
5182 |                 ]);
5183 |                 leftContent = results[0];
5184 |                 rightContent = results[1];
5185 |             }
5186 | 
5187 |             let mode = "ace/mode/text";
5188 |             if (data.file.endsWith('.js')) mode = "ace/mode/javascript";
5189 |             else if (data.file.endsWith('.html')) mode = "ace/mode/html";
5190 |             else if (data.file.endsWith('.css')) mode = "ace/mode/css";
5191 |             else if (data.file.endsWith('.json')) mode = "ace/mode/json";
5192 |             else if (data.file.endsWith('.md')) mode = "ace/mode/markdown";
5193 |             
5194 |             diffLeft.session.setMode(mode);
5195 |             diffLeft.setValue(leftContent, -1);
5196 |             
5197 |             diffRight.session.setMode(mode);
5198 |             diffRight.setValue(rightContent, -1);
5199 | 
5200 |             const Range = ace.require('ace/range').Range;
5201 | 
5202 |             // Helper to get Range from String Index
5203 |             const getRangeFromText = (session, searchText) => {
5204 |                 const fullText = session.getValue();
5205 |                 // 1. Try Exact Match
5206 |                 let startIdx = fullText.indexOf(searchText);
5207 |                 
5208 |                 // 2. Try Robust Match (Ignoring Line Endings differences)
5209 |                 if (startIdx === -1) {
5210 |                     const clean = (s) => s.replace(/\r\n/g, '\n').trim();
5211 |                     startIdx = clean(fullText).indexOf(clean(searchText));
5212 |                 }
5213 | 
5214 |                 if (startIdx !== -1) {
5215 |                     const linesBefore = fullText.substring(0, startIdx).split('\n');
5216 |                     const startRow = linesBefore.length - 1;
5217 |                     const startCol = linesBefore[startRow].length;
5218 |                     const linesInSearch = searchText.split('\n');
5219 |                     const endRow = startRow + linesInSearch.length - 1;
5220 |                     const endCol = linesInSearch.length > 1 ? linesInSearch[linesInSearch.length - 1].length : startCol + searchText.length;
5221 |                     return new Range(startRow, startCol, endRow, endCol);
5222 |                 }
5223 |                 return null;
5224 |             };
5225 |             
5226 |             const searchRemove = data.op.find_block || data.op.anchor;
5227 |             if(searchRemove) {
5228 |                 const range = getRangeFromText(diffLeft.session, String(searchRemove));
5229 |                 if(range) {
5230 |                     diffLeft.session.addMarker(range, "marker-remove", "fullLine");
5231 |                     diffLeft.scrollToLine(range.start.row, true, true, function() {});
5232 |                 }
5233 |             }
5234 | 
5235 |             const searchAdd = data.op.replace_with || data.op.content;
5236 |             if(searchAdd) {
