5239 |                     diffRight.session.addMarker(range, "marker-add", "fullLine");
5240 |                     diffRight.scrollToLine(range.start.row, true, true, function() {});
5241 |                 }
5242 |             }
5243 | 
5244 |         } catch(e) {
5245 |             diffLeft.setValue("Error: " + e.message, -1);
5246 |         }
5247 |     }
