1327 |     function smartJSONParse(jsonString) {
1328 |         try {
1329 |             return JSON.parse(jsonString);
1330 |         } catch (e) {
1331 |             console.warn("Standard JSON parse failed, attempting Robust Auto-Fix...");
1332 |             let fixed = jsonString
1333 |                 // 1. Fix backslashes that aren't part of a valid escape sequence
1334 |                 .replace(/\\(?!["\\/bfnrtu])/g, "\\\\")
1335 |                 // 2. Fix literal newlines inside strings (replace with \n)
