1337 |                     // Only replace if we are likely inside a quoted string
1338 |                     const before = jsonString.slice(0, offset);
1339 |                     const quoteCount = (before.match(/"/g) || []).length;
1340 |                     return (quoteCount % 2 === 1) ? "\\n" : "\n";
1341 |                 });
1342 | 
1343 |             try {
1344 |                 const cleanObj = JSON.parse(fixed);
1345 |                 document.getElementById('json-input').value = fixed;
1346 |                 if (typeof saveState === 'function') saveState();
1347 |                 showGlobalToast("✨ Robust Auto-Correction Applied");
1348 |                 return cleanObj;
