1373 |     function resolvePath(base, relative) {
1374 |         const stack = base.split('/');
1375 |         stack.pop(); 
1376 |         const parts = relative.split('/');
1377 |         for (let i = 0; i < parts.length; i++) {
1378 |             if (parts[i] === '.') continue;
1379 |             if (parts[i] === '..') stack.pop();
1380 |             else stack.push(parts[i]);
1381 |         }
1382 |         return stack.join('/');
1383 |     }
