1612 |     async function runAutoFixLoop(name, code, errorList) {
1613 |         const status = document.getElementById('ef-status-msg');
1614 |         let currentCode = code;
1615 |         let currentErrors = errorList;
1616 | 
1617 |         // Fix one by one (recursive loop)
1618 |         async function fixNext(index) {
1619 |             if (index >= currentErrors.length) return true; // All initial errors processed
1620 | 
1621 |             const err = currentErrors[index];
1622 |             status.innerText = `🔧 Fixing Error ${index + 1}/${currentErrors.length} (Line ${err.line})...`;
1623 |             status.style.color = "#eab308"; // Dev yellow
1624 | 
1625 |             try {
1626 |                 // 1. Get Patch from AI
1627 |                 const res = await fetch(CONFIG.funcUrl, { 
1628 |                     method: 'POST', 
1629 |                     headers: {'Content-Type': 'application/json'},
1630 |                     body: apiBody({ 
1631 |                         action: 'propose_syntax_fix', 
1632 |                         code: currentCode, 
1633 |                         error: err 
1634 |                     })
1635 |                 });
1636 |                 const data = await res.json();
1637 |                 const ops = data.operations;
1638 | 
1639 |                 if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");
1640 | 
1641 |                 // 2. Apply Patch Locally
1642 |                 const patchResult = applyLocalPatch(currentCode, ops);
1643 |                 if (!patchResult.success) throw new Error("Generated patch did not match code.");
1644 | 
1645 |                 currentCode = patchResult.content;
1646 |                 document.getElementById('ef-code').value = currentCode; // Update UI
1647 | 
1648 |                 // 3. Re-Validate
1649 |                 const scanRes = await fetch(CONFIG.funcUrl, { 
1650 |                     method: 'POST', headers: {'Content-Type': 'application/json'},
1651 |                     body: apiBody({ action: 'validate_syntax_deep', code_block: currentCode, file_path: 'index.ts' })
1652 |                 });
1653 |                 const scanData = await scanRes.json();
1654 | 
1655 |                 if (scanData.valid) {
1656 |                     status.innerText = "✅ Syntax Fixed!";
1657 |                     return true;
1658 |                 } else {
1659 |                     // If errors remain, update list and Prompt user
1660 |                     currentErrors = scanData.errors;
1661 |                     if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
1662 |                         // Recursively fix the *new* first error (since layout changed)
1663 |                         return await fixNext(0);
1664 |                     } else {
1665 |                         return false;
1666 |                     }
1667 |                 }
1668 | 
1669 |             } catch (e) {
1670 |                 if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
1671 |                     return await fixNext(index);
1672 |                 } else {
1673 |                     return false;
1674 |                 }
1675 |             }
1676 |         }
1677 | 
1678 |         return await fixNext(0);
1679 |     }
