3747 |                 if (f.time === 'hour' && diff > 3600000) return false;
3748 |                 if (f.time === 'today' && diff > 86400000) return false;
3749 |                 if (f.time === 'week' && diff > 604800000) return false;
3750 |             }
3751 | 
3752 |             // 2. File Filter
3753 |             if (f.files.length > 0) {
3754 |                 let touchedFiles = [];
3755 |                 if (tab === 'history') touchedFiles = (item.ops || []).map(o => o.file_path || '');
3756 |                 if (tab === 'patcher') {
3757 |                     // Patcher logic is handled by applyFiltersToPatcher, but we add safety here
3758 |                     touchedFiles = (item.results || []).map(r => r.file);
3759 |                 }
3760 |                 if (tab === 'cicd') {
3761 |                     const match = dbHistory.find(h => h.sha === item.head_commit.id);
3762 |                     touchedFiles = match ? (match.ops || []).map(o => o.file_path || '') : [];
3763 |                 }
3764 |                 // Filter out empty paths
3765 |                 touchedFiles = touchedFiles.filter(p => p !== '');
3766 |                 if (touchedFiles.length > 0 && !touchedFiles.some(tf => f.files.includes(tf))) return false;
3767 |             }
3768 |             return true;
3769 |         });
