4053 |     // --- GENERIC UI ---
4054 |     function formatBytes(bytes) {
4055 |         if (!bytes) return '0 B';
4056 |         const k = 1024;
4057 |         const sizes = ['B', 'KB', 'MB', 'GB'];
4058 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
4059 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
4060 |     }
