4062 |     function timeAgo(dateString) {
4063 |         const date = new Date(dateString);
4064 |         const now = new Date();
4065 |         const seconds = Math.floor((now - date) / 1000);
4066 |         if (seconds < 10) return 'just now';
4067 |         if (seconds < 60) return seconds + 's ago';
4068 |         const minutes = Math.floor(seconds / 60);
4069 |         if (minutes < 60) return minutes + 'm ago';
4070 |         const hours = Math.floor(minutes / 60);
4071 |         if (hours < 24) return hours + 'h ago';
4072 |         return date.toLocaleDateString();
4073 |     }
