4212 |                     offsetTop += curr.offsetTop;
4213 |                     curr = curr.offsetParent;
4214 |                 }
4215 | 
4216 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
4217 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
4218 | 
4219 |                 // Visual Highlight
