4229 |                 return true;
4230 |             }
4231 | 
4232 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
4233 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
4234 |                 retryCount++;
4235 |                 showGlobalToast("🔍 Searching deeper...");
4236 |                 
4237 |                 await loadMoreFn(); 
4238 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
4239 |                 return attemptNavigation();
4240 |             }
4241 | 
4242 |             console.error("[DeepJump] Failed: Element not found after retries.");
4243 |             showGlobalToast("Entry not found in recent history.", true);
4244 |             console.groupEnd();
4245 |             return false;
