function openInspector() { document.getElementById('inspector-overlay').classList.add('active'); toggleFab(false); }
function closeInspector() { document.getElementById('inspector-overlay').classList.remove('active'); toggleFab(true); }
function clearInspector() {
    inspectorLogData = []; inspectorNetData = [];
    document.getElementById('ins-view-console').innerHTML = '';
    document.getElementById('ins-net-list').innerHTML = '';
}
function switchInsTab(tab, btn) {
    document.querySelectorAll('.ins-tab').forEach(t => {
        t.classList.remove('active'); t.style.background = 'transparent'; t.style.borderColor = 'var(--border)';
    });
    document.querySelectorAll('.ins-content').forEach(c => c.style.display = 'none');
    btn.classList.add('active'); btn.style.background = 'rgba(59,130,246,0.1)'; btn.style.borderColor = 'var(--primary)';
    document.getElementById('ins-view-' + tab).style.display = 'block';
}

function copyInsEntry(btn) {
    const row = btn.closest('.ins-row');
    const details = row.querySelector('.ins-net-details.open');
    const text = details ? details.innerText.replace('Copy JSON', '') : row.innerText.replace('Copy', '');
    navigator.clipboard.writeText(text.trim()).then(() => {
        const oldText = btn.innerText; btn.innerText = 'Copied'; setTimeout(() => btn.innerText = oldText, 1000);
    });
}

function copyActiveInspectorData() {
    const activeBtn = document.querySelector('.ins-tab.active');
    const activeTab = activeBtn.innerText.toLowerCase();
    let text = "";
    if(activeTab === 'console') {
        text = inspectorLogData.map(l => `[${l.time}] ${l.msg}`).join('\n');
    } else {
        text = inspectorNetData.map(n => `${n.method} ${n.status} ${n.url} (${n.duration}ms)`).join('\n');
    }
    navigator.clipboard.writeText(text).then(() => showGlobalToast(`Copied all ${activeTab} data`));
}

function renderJsonHighlight(obj) {
    if (!obj) return '<span style="color:#444">null</span>';
    const str = typeof obj === 'string' ? obj : JSON.stringify(obj, null, 2);
    const html = escapeHtml(str).replace(/"(\w+)":/g, '<span class="json-key">"$1"</span>:')
                     .replace(/: "(.*?)"/g, ': <span class="json-string">"$1"</span>')
                     .replace(/: (\d+)/g, ': <span class="json-number">$1</span>');
    return `<pre style="margin:0; font-size:10px; color:#ccc; white-space:pre-wrap; word-break:break-all;">${html}</pre>`;
}

