1276 |     /**
1277 |      * Tries to parse JSON. If it fails due to bad escaping (common with AI),
1278 |      * it attempts to double-escape backslashes that aren't valid JSON control chars.
1279 |      */
1280 |     function smartJSONParse(jsonString) {
1281 |         try {
1282 |             return JSON.parse(jsonString);
1283 |         } catch (e) {
1284 |             console.warn("Standard JSON parse failed, attempting Robust Auto-Fix...");
1285 |             let fixed = jsonString
1286 |                 // 1. Fix backslashes that aren't part of a valid escape sequence
1287 |                 .replace(/\\(?!["\\/bfnrtu])/g, "\\\\")
1288 |                 // 2. Fix literal newlines inside strings (replace with \n)
1289 |                 .replace(/(\n)/g, (match, p1, offset) => {
1290 |                     // Only replace if we are likely inside a quoted string
1291 |                     const before = jsonString.slice(0, offset);
1292 |                     const quoteCount = (before.match(/"/g) || []).length;
1293 |                     return (quoteCount % 2 === 1) ? "\\n" : "\n";
1294 |                 });
1295 | 
1296 |             try {
1297 |                 const cleanObj = JSON.parse(fixed);
1298 |                 document.getElementById('json-input').value = fixed;
1299 |                 if (typeof saveState === 'function') saveState();
1300 |                 showGlobalToast("✨ Robust Auto-Correction Applied");
1301 |                 return cleanObj;
1302 |             } catch (e2) {
1303 |                 console.error("Robust fix failed:", e2);
1304 |                 throw e; // Throw original error for better debugging
1305 |             }
1306 |         }
1307 |     }
