1309 |     function b64DecodeUnicode(str) {
1310 |         return decodeURIComponent(atob(str).split('').map(function(c) {
1311 |             return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
1312 |         }).join(''));
1313 |     }
1314 | 
1315 |     // Unicode-Safe Encoder for AI Context
1316 |     function b64EncodeUnicode(str) {
1317 |         return btoa(encodeURIComponent(str).replace(/%([0-9A-F]{2})/g,
1318 |             function toSolidBytes(match, p1) { return String.fromCharCode('0x' + p1); }));
1319 |     }
