1326 |     function resolvePath(base, relative) {
1327 |         const stack = base.split('/');
1328 |         stack.pop(); 
1329 |         const parts = relative.split('/');
1330 |         for (let i = 0; i < parts.length; i++) {
1331 |             if (parts[i] === '.') continue;
1332 |             if (parts[i] === '..') stack.pop();
1333 |             else stack.push(parts[i]);
1334 |         }
1335 |         return stack.join('/');
1336 |     }
