1565 |     async function runAutoFixLoop(name, code, errorList) {
1566 |         const status = document.getElementById('ef-status-msg');
1567 |         let currentCode = code;
1568 |         let currentErrors = errorList;
1569 | 
1570 |         // Fix one by one (recursive loop)
1571 |         async function fixNext(index) {
1572 |             if (index >= currentErrors.length) return true; // All initial errors processed
1573 | 
1574 |             const err = currentErrors[index];
1575 |             status.innerText = `🔧 Fixing Error ${index + 1}/${currentErrors.length} (Line ${err.line})...`;
1576 |             status.style.color = "#eab308"; // Dev yellow
1577 | 
1578 |             try {
1579 |                 // 1. Get Patch from AI
1580 |                 const res = await fetch(CONFIG.funcUrl, { 
1581 |                     method: 'POST', 
1582 |                     headers: {'Content-Type': 'application/json'},
1583 |                     body: apiBody({ 
1584 |                         action: 'propose_syntax_fix', 
1585 |                         code: currentCode, 
1586 |                         error: err 
1587 |                     })
1588 |                 });
1589 |                 const data = await res.json();
1590 |                 const ops = data.operations;
1591 | 
1592 |                 if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");
1593 | 
1594 |                 // 2. Apply Patch Locally
1595 |                 const patchResult = applyLocalPatch(currentCode, ops);
1596 |                 if (!patchResult.success) throw new Error("Generated patch did not match code.");
1597 | 
1598 |                 currentCode = patchResult.content;
1599 |                 document.getElementById('ef-code').value = currentCode; // Update UI
1600 | 
1601 |                 // 3. Re-Validate
1602 |                 const scanRes = await fetch(CONFIG.funcUrl, { 
1603 |                     method: 'POST', headers: {'Content-Type': 'application/json'},
1604 |                     body: apiBody({ action: 'validate_syntax_deep', code_block: currentCode, file_path: 'index.ts' })
1605 |                 });
1606 |                 const scanData = await scanRes.json();
1607 | 
1608 |                 if (scanData.valid) {
1609 |                     status.innerText = "✅ Syntax Fixed!";
1610 |                     return true;
1611 |                 } else {
1612 |                     // If errors remain, update list and Prompt user
1613 |                     currentErrors = scanData.errors;
1614 |                     if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
1615 |                         // Recursively fix the *new* first error (since layout changed)
1616 |                         return await fixNext(0);
1617 |                     } else {
1618 |                         return false;
1619 |                     }
1620 |                 }
1621 | 
1622 |             } catch (e) {
1623 |                 if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
1624 |                     return await fixNext(index);
1625 |                 } else {
1626 |                     return false;
1627 |                 }
1628 |             }
1629 |         }
1630 | 
1631 |         return await fixNext(0);
1632 |     }
