3946 |     function formatBytes(bytes) {
3947 |         if (!bytes) return '0 B';
3948 |         const k = 1024;
3949 |         const sizes = ['B', 'KB', 'MB', 'GB'];
3950 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
3951 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
3952 |     }
