3954 |     function timeAgo(dateString) {
3955 |         const date = new Date(dateString);
3956 |         const now = new Date();
3957 |         const seconds = Math.floor((now - date) / 1000);
3958 |         if (seconds < 10) return 'just now';
3959 |         if (seconds < 60) return seconds + 's ago';
3960 |         const minutes = Math.floor(seconds / 60);
3961 |         if (minutes < 60) return minutes + 'm ago';
3962 |         const hours = Math.floor(minutes / 60);
3963 |         if (hours < 24) return hours + 'h ago';
3964 |         return date.toLocaleDateString();
3965 |     }
