4082 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
4083 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
4084 |         
4085 |         const navItems = document.querySelectorAll('.nav-item');
4086 |         switchTab(tabId, navItems[navIndex]);
4087 | 
4088 |         const scrollContainer = document.querySelector('.main-view');
4089 |         let retryCount = 0;
4090 |         const MAX_RETRIES = 5;
4091 | 
4092 |         const attemptNavigation = async () => {
4093 |             const element = document.querySelector(selector);
4094 |             
4095 |             if (element) {
4096 |                 console.log("[DeepJump] Element found. Scrolling...");
4097 |                 
4098 |                 // Wait for any tab transition animations
4099 |                 await new Promise(r => setTimeout(r, 300));
4100 | 
4101 |                 let offsetTop = 0;
4102 |                 let curr = element;
4103 |                 while (curr && curr !== scrollContainer) {
4104 |                     offsetTop += curr.offsetTop;
4105 |                     curr = curr.offsetParent;
4106 |                 }
4107 | 
4108 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
4109 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
4110 | 
4111 |                 // Visual Highlight
4112 |                 element.style.transition = 'all 0.5s ease';
4113 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
4114 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
4115 |                 setTimeout(() => {
4116 |                     element.style.backgroundColor = '';
4117 |                     element.style.boxShadow = '';
4118 |                 }, 3000);
4119 |                 
4120 |                 console.groupEnd();
4121 |                 return true;
4122 |             }
4123 | 
4124 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
4125 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
4126 |                 retryCount++;
4127 |                 showGlobalToast("🔍 Searching deeper...");
4128 |                 
4129 |                 await loadMoreFn(); 
4130 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
4131 |                 return attemptNavigation();
4132 |             }
4133 | 
4134 |             console.error("[DeepJump] Failed: Element not found after retries.");
4135 |             showGlobalToast("Entry not found in recent history.", true);
4136 |             console.groupEnd();
4137 |             return false;
4138 |         };
4139 | 
4140 |         setTimeout(attemptNavigation, 100);
4141 |     }
