1508 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
1509 |     function applyLocalPatch(content, ops) {
1510 |         let lines = content.split('\n');
1511 |         let logs = [];
1512 |         let success = true;
1513 | 
1514 |         if (typeof ops === 'string') {
1515 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
1516 |         }
1517 | 
1518 |         ops.forEach(op => {
1519 |             if (op.action === 'comment') return;
1520 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
1521 |             
1522 |             if (op.action === 'replace_block') {
1523 |                 // Strategy 1: Exact String Match (Fastest)
1524 |                 const currentStr = lines.join('\n');
1525 |                 if (currentStr.includes(op.find_block)) {
1526 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
1527 |                     logs.push('Exact match applied');
1528 |                     return;
1529 |                 }
1530 | 
1531 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
1532 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
1533 |                 if (searchLines.length === 0) return;
1534 | 
1535 |                 let matchStart = -1;
1536 |                 let matchEnd = -1;
1537 | 
1538 |                 // Scan file lines
1539 |                 for (let i = 0; i < lines.length; i++) {
1540 |                     // If first line matches (ignoring whitespace)
1541 |                     if (lines[i].trim() === searchLines[0]) {
1542 |                         // Check subsequent lines
1543 |                         let allMatch = true;
1544 |                         let fileOffset = 0;
1545 |                         let searchOffset = 1;
1546 |                         
1547 |                         while (searchOffset < searchLines.length) {
1548 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
1549 |                             const nextFile = lines[i + fileOffset + 1].trim();
1550 |                             // Skip empty lines in file if they aren't in search block
1551 |                             if (nextFile === '') {
1552 |                                 fileOffset++;
1553 |                                 continue;
1554 |                             }
1555 |                             if (nextFile !== searchLines[searchOffset]) {
1556 |                                 allMatch = false;
1557 |                                 break;
1558 |                             }
1559 |                             fileOffset++;
1560 |                             searchOffset++;
1561 |                         }
1562 | 
1563 |                         if (allMatch) {
1564 |                             matchStart = i;
1565 |                             matchEnd = i + fileOffset;
1566 |                             break;
1567 |                         }
1568 |                     }
1569 |                 }
1570 | 
1571 |                 if (matchStart !== -1) {
1572 |                     // Replace the range of lines
1573 |                     const replacement = op.replace_with.split('\n');
1574 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
1575 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
1576 |                 } else {
1577 |                     success = false;
1578 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
1579 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
1580 |                 }
1581 |             }
1582 |         });
1583 |         return { content: lines.join('\n'), success, logs };
1584 |     }
