1588 |     async function runAutoFixLoop(name, code, errorList) {
1589 |         const status = document.getElementById('ef-status-msg');
1590 |         let currentCode = code;
1591 |         let currentErrors = errorList;
1592 | 
1593 |         // Fix one by one (recursive loop)
1594 |         async function fixNext(index) {
1595 |             if (index >= currentErrors.length) return true; // All initial errors processed
1596 | 
1597 |             const err = currentErrors[index];
1598 |             status.innerText = `🔧 Fixing Error ${index + 1}/${currentErrors.length} (Line ${err.line})...`;
1599 |             status.style.color = "#eab308"; // Dev yellow
1600 | 
1601 |             try {
1602 |                 // 1. Get Patch from AI
1603 |                 const res = await fetch(CONFIG.funcUrl, { 
1604 |                     method: 'POST', 
1605 |                     headers: {'Content-Type': 'application/json'},
1606 |                     body: apiBody({ 
1607 |                         action: 'propose_syntax_fix', 
1608 |                         code: currentCode, 
1609 |                         error: err 
1610 |                     })
1611 |                 });
1612 |                 const data = await res.json();
1613 |                 const ops = data.operations;
1614 | 
1615 |                 if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");
1616 | 
1617 |                 // 2. Apply Patch Locally
1618 |                 const patchResult = applyLocalPatch(currentCode, ops);
1619 |                 if (!patchResult.success) throw new Error("Generated patch did not match code.");
1620 | 
1621 |                 currentCode = patchResult.content;
1622 |                 document.getElementById('ef-code').value = currentCode; // Update UI
1623 | 
1624 |                 // 3. Re-Validate
1625 |                 const scanRes = await fetch(CONFIG.funcUrl, { 
1626 |                     method: 'POST', headers: {'Content-Type': 'application/json'},
1627 |                     body: apiBody({ action: 'validate_syntax_deep', code_block: currentCode, file_path: 'index.ts' })
1628 |                 });
1629 |                 const scanData = await scanRes.json();
1630 | 
1631 |                 if (scanData.valid) {
1632 |                     status.innerText = "✅ Syntax Fixed!";
1633 |                     return true;
1634 |                 } else {
1635 |                     // If errors remain, update list and Prompt user
1636 |                     currentErrors = scanData.errors;
1637 |                     if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
1638 |                         // Recursively fix the *new* first error (since layout changed)
1639 |                         return await fixNext(0);
1640 |                     } else {
1641 |                         return false;
1642 |                     }
1643 |                 }
1644 | 
1645 |             } catch (e) {
1646 |                 if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
1647 |                     return await fixNext(index);
1648 |                 } else {
1649 |                     return false;
1650 |                 }
1651 |             }
1652 |         }
1653 | 
1654 |         return await fixNext(0);
1655 |     }
