3968 |     // --- GENERIC UI ---
3969 |     function formatBytes(bytes) {
3970 |         if (!bytes) return '0 B';
3971 |         const k = 1024;
3972 |         const sizes = ['B', 'KB', 'MB', 'GB'];
3973 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
3974 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
3975 |     }
3976 | 
3977 |     function timeAgo(dateString) {
3978 |         const date = new Date(dateString);
3979 |         const now = new Date();
3980 |         const seconds = Math.floor((now - date) / 1000);
3981 |         if (seconds < 10) return 'just now';
3982 |         if (seconds < 60) return seconds + 's ago';
3983 |         const minutes = Math.floor(seconds / 60);
3984 |         if (minutes < 60) return minutes + 'm ago';
3985 |         const hours = Math.floor(minutes / 60);
3986 |         if (hours < 24) return hours + 'h ago';
3987 |         return date.toLocaleDateString();
3988 |     }
