4109 |         switchTab(tabId, navItems[navIndex]);
4110 | 
4111 |         const scrollContainer = document.querySelector('.main-view');
4112 |         let retryCount = 0;
4113 |         const MAX_RETRIES = 5;
4114 | 
4115 |         const attemptNavigation = async () => {
4116 |             const element = document.querySelector(selector);
4117 |             
4118 |             if (element) {
4119 |                 console.log("[DeepJump] Element found. Scrolling...");
4120 |                 
4121 |                 // Wait for any tab transition animations
4122 |                 await new Promise(r => setTimeout(r, 300));
4123 | 
4124 |                 let offsetTop = 0;
4125 |                 let curr = element;
4126 |                 while (curr && curr !== scrollContainer) {
4127 |                     offsetTop += curr.offsetTop;
4128 |                     curr = curr.offsetParent;
4129 |                 }
4130 | 
4131 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
4132 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
4133 | 
4134 |                 // Visual Highlight
4135 |                 element.style.transition = 'all 0.5s ease';
4136 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
4137 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
4138 |                 setTimeout(() => {
