4140 |                     element.style.boxShadow = '';
4141 |                 }, 3000);
4142 |                 
4143 |                 console.groupEnd();
4144 |                 return true;
4145 |             }
4146 | 
4147 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
4148 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
4149 |                 retryCount++;
4150 |                 showGlobalToast("🔍 Searching deeper...");
4151 |                 
4152 |                 await loadMoreFn(); 
4153 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
4154 |                 return attemptNavigation();
4155 |             }
4156 | 
4157 |             console.error("[DeepJump] Failed: Element not found after retries.");
4158 |             showGlobalToast("Entry not found in recent history.", true);
4159 |             console.groupEnd();
4160 |             return false;
4161 |         };
4162 | 
4163 |         setTimeout(attemptNavigation, 100);
