1535 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
1536 |     function applyLocalPatch(content, ops) {
1537 |         let lines = content.split('\n');
1538 |         let logs = [];
1539 |         let success = true;
1540 | 
1541 |         if (typeof ops === 'string') {
1542 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
1543 |         }
1544 | 
1545 |         ops.forEach(op => {
1546 |             if (op.action === 'comment') return;
1547 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
1548 |             
1549 |             if (op.action === 'replace_block') {
1550 |                 // Strategy 1: Exact String Match (Fastest)
1551 |                 const currentStr = lines.join('\n');
1552 |                 if (currentStr.includes(op.find_block)) {
1553 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
1554 |                     logs.push('Exact match applied');
1555 |                     return;
1556 |                 }
1557 | 
1558 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
1559 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
1560 |                 if (searchLines.length === 0) return;
1561 | 
1562 |                 let matchStart = -1;
1563 |                 let matchEnd = -1;
1564 | 
1565 |                 // Scan file lines
1566 |                 for (let i = 0; i < lines.length; i++) {
1567 |                     // If first line matches (ignoring whitespace)
1568 |                     if (lines[i].trim() === searchLines[0]) {
1569 |                         // Check subsequent lines
1570 |                         let allMatch = true;
1571 |                         let fileOffset = 0;
1572 |                         let searchOffset = 1;
1573 |                         
1574 |                         while (searchOffset < searchLines.length) {
1575 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
1576 |                             const nextFile = lines[i + fileOffset + 1].trim();
1577 |                             // Skip empty lines in file if they aren't in search block
1578 |                             if (nextFile === '') {
1579 |                                 fileOffset++;
1580 |                                 continue;
1581 |                             }
1582 |                             if (nextFile !== searchLines[searchOffset]) {
1583 |                                 allMatch = false;
1584 |                                 break;
1585 |                             }
1586 |                             fileOffset++;
1587 |                             searchOffset++;
1588 |                         }
1589 | 
1590 |                         if (allMatch) {
1591 |                             matchStart = i;
1592 |                             matchEnd = i + fileOffset;
1593 |                             break;
1594 |                         }
1595 |                     }
1596 |                 }
1597 | 
1598 |                 if (matchStart !== -1) {
1599 |                     // Replace the range of lines
1600 |                     const replacement = op.replace_with.split('\n');
1601 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
1602 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
1603 |                 } else {
1604 |                     success = false;
1605 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
1606 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
1607 |                 }
1608 |             }
1609 |         });
1610 |         return { content: lines.join('\n'), success, logs };
1611 |     }
