4132 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
4133 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
4134 |         
4135 |         const navItems = document.querySelectorAll('.nav-item');
4136 |         switchTab(tabId, navItems[navIndex]);
4137 | 
4138 |         const scrollContainer = document.querySelector('.main-view');
4139 |         let retryCount = 0;
4140 |         const MAX_RETRIES = 5;
4141 | 
4142 |         const attemptNavigation = async () => {
4143 |             const element = document.querySelector(selector);
4144 |             
4145 |             if (element) {
4146 |                 console.log("[DeepJump] Element found. Scrolling...");
4147 |                 
4148 |                 // Wait for any tab transition animations
4149 |                 await new Promise(r => setTimeout(r, 300));
4150 | 
4151 |                 let offsetTop = 0;
4152 |                 let curr = element;
4153 |                 while (curr && curr !== scrollContainer) {
4154 |                     offsetTop += curr.offsetTop;
4155 |                     curr = curr.offsetParent;
4156 |                 }
4157 | 
4158 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
4159 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
4160 | 
4161 |                 // Visual Highlight
4162 |                 element.style.transition = 'all 0.5s ease';
4163 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
4164 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
4165 |                 setTimeout(() => {
4166 |                     element.style.backgroundColor = '';
4167 |                     element.style.boxShadow = '';
4168 |                 }, 3000);
4169 |                 
4170 |                 console.groupEnd();
4171 |                 return true;
4172 |             }
4173 | 
4174 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
4175 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
4176 |                 retryCount++;
4177 |                 showGlobalToast("🔍 Searching deeper...");
4178 |                 
4179 |                 await loadMoreFn(); 
4180 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
4181 |                 return attemptNavigation();
4182 |             }
4183 | 
4184 |             console.error("[DeepJump] Failed: Element not found after retries.");
4185 |             showGlobalToast("Entry not found in recent history.", true);
4186 |             console.groupEnd();
4187 |             return false;
4188 |         };
4189 | 
4190 |         setTimeout(attemptNavigation, 100);
4191 |     }
